136→    const attachment = nextWall[attachmentKey];
137→    if (!attachment) continue;
138→
139→    const column = findColumn(columns, attachment.columnId);
140→    if (!column) {
141→      nextWall = { ...nextWall, [attachmentKey]: null };
142→      continue;
143→    }
144→
145→    const point = resolveColumnAttachmentPoint(column, attachment);
146→    if (!point) {
147→      nextWall = { ...nextWall, [attachmentKey]: null };
148→      continue;
149→    }
150→
151→    nextWall = {
152→      ...nextWall,
153→      [endpoint]: point,
154→      [attachmentKey]: cloneAttachment(attachment),
155→    };
156→  }
157→
158→  return nextWall;
159→}
