 22→function raySegmentIntersection(origin, direction, start, end) {
 23→  const segment = subtract(end, start);
 24→  const cross = direction.x * segment.y - direction.y * segment.x;
 25→  if (Math.abs(cross) < EPSILON) return null;
 26→
 27→  const delta = subtract(start, origin);
 28→  const t = (delta.x * segment.y - delta.y * segment.x) / cross;
 29→  const u = (delta.x * direction.y - delta.y * direction.x) / cross;
 30→
 31→  if (t < -EPSILON || u < -EPSILON || u > 1 + EPSILON) return null;
 32→
 33→  return {
 34→    t,
 35→    point: add(origin, scale(direction, Math.max(0, t))),
 36→  };
 37→}
 38→
 39→function trimPoint(origin, otherPoint, column) {
 40→  if (!column) return { ...origin };
 41→
 42→  const direction = normalize(subtract(otherPoint, origin));
 43→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) {
 44→    return { ...origin };
 45→  }
 46→
 47→  const polygon = columnOutline(column);
 48→  let best = null;
 49→
 50→  for (let i = 0; i < polygon.length; i += 1) {
 51→    const hit = raySegmentIntersection(origin, direction, polygon[i], polygon[(i + 1) % polygon.length]);
 52→    if (!hit) continue;
 53→    if (!best || hit.t < best.t) {
 54→      best = hit;
 55→    }
 56→  }
 57→
 58→  return best ? best.point : { ...origin };
 59→}
