25→export function projectPointToSectionCut(sectionCut, point) {
26→  const origin = sectionCut?.startPoint || { x: 0, y: 0 };
27→  const relative = subtract(point, origin);
28→  const normal = sectionCutNormal(sectionCut);
29→  const viewAxis = sectionCutViewAxis(sectionCut);
30→  const start = sectionCut?.startPoint || { x: 0, y: 0 };
31→  const end = sectionCut?.endPoint || { x: 0, y: 0 };
32→  const startAlong = start.x * viewAxis.x + start.y * viewAxis.y;
33→  const endAlong = end.x * viewAxis.x + end.y * viewAxis.y;
34→  const pointAlong = point.x * viewAxis.x + point.y * viewAxis.y;
35→  const minAlong = Math.min(startAlong, endAlong);
36→
37→  return {
38→    along: pointAlong - minAlong,
39→    offset: relative.x * normal.x + relative.y * normal.y,
40→  };
